// Mock Supabase para desarrollo sin configuración real
const authStateListeners = new Set();
let currentUser = null;

const notifyAuthState = () => {
  authStateListeners.forEach((listener) => {
    try { listener('SIGNED_IN', { user: currentUser }); } catch (_) {}
  });
};

export const supabase = {
  auth: {
    get user() {
      return currentUser;
    },
    onAuthStateChange: (callback) => {
      authStateListeners.add(callback);
      // Notificar inmediatamente
      callback('INITIAL_SESSION', { user: currentUser });
      return {
        data: {
          subscription: { unsubscribe: () => authStateListeners.delete(callback) }
        }
      };
    },
    signInWithPassword: async ({ email, password }) => {
      if (email === 'apoyotic@todoporunalma.org' && password === '12345') {
        currentUser = {
          id: 'mock-apoyotic',
          email,
          user_metadata: { full_name: 'Apoyo TIC' },
        };
        notifyAuthState();
        return { data: { user: currentUser, session: { access_token: 'mock-token' } }, error: null };
      }
      return { data: { user: null, session: null }, error: { message: 'Credenciales inválidas (mock).' } };
    },
    signUp: async ({ email, password }) => {
      currentUser = { id: 'mock-' + Date.now(), email, user_metadata: { full_name: email.split('@')[0] } };
      notifyAuthState();
      return { data: { user: currentUser }, error: null };
    },
    signOut: async () => {
      currentUser = null;
      notifyAuthState();
      return { error: null };
    },
    resetPasswordForEmail: async (email) => {
      console.log('Mock supabase: password reset para', email);
      return { data: {}, error: null };
    },
    signInWithOAuth: async ({ provider }) => {
      if (provider === 'google') {
        currentUser = {
          id: 'mock-google-user',
          email: 'google@todoporunalma.org',
          user_metadata: { full_name: 'Usuario Google' }
        };
        notifyAuthState();
        return { data: { user: currentUser }, error: null };
      }
      return { data: { user: null }, error: { message: 'Provider no soportado en mock' } };
    }
  }
};

// Funciones de autenticación simplificadas para mock
export const auth = {
  signInWithPassword: (email, password) => supabase.auth.signInWithPassword({ email, password }),
  signUp: (email, password) => supabase.auth.signUp({ email, password }),
  signOut: () => supabase.auth.signOut(),
  resetPasswordForEmail: (email) => supabase.auth.resetPasswordForEmail(email),
  onAuthStateChange: (callback) => supabase.auth.onAuthStateChange(callback),
  signInWithGoogle: () => supabase.auth.signInWithOAuth({ provider: 'google' })
};

export default supabase;
